    else {
        // 情况 3: 第 k 小元素在右子树
        // 注意：k 的值需要调整。去掉左子树的 L 个和根结点 1 个，共 L+1 个。
        // 在右子树中找第 k - (L+1) 小的元素。
        return FindKthSmallest(T->rchild, k - (L + 1));
    }
}

