// 辅助函数：创建一个新的结点
BSTNode* CreateNode(int data) {
    BSTNode *newNode = (BSTNode*)malloc(sizeof(BSTNode));
    newNode->data = data;
    newNode->lchild = newNode->rchild = NULL;
    newNode->count = 1; // 初始 count 为 1
