}

// 辅助函数：手动构建一棵树 (为了演示方便，不写复杂的 count 更新逻辑)
//      5(c:6)
//     / \
//  2(c:3) 8(c:2)
// / \    /
//1(c:1) 3(c:1) 7(c:1)
// 排序后的序列: 1, 2, 3, 5, 7, 8
BSTree BuildSampleTree() {
    BSTree root = CreateNode(5);
    root->lchild = CreateNode(2);
    root->rchild = CreateNode(8);
    root->lchild->lchild = CreateNode(1);
    root->lchild->rchild = CreateNode(3);
    root->rchild->lchild = CreateNode(7);

    // 手动更新 count 
    root->lchild->lchild->count = 1;
    root->lchild->rchild->count = 1;
    root->rchild->lchild->count = 1;
    root->lchild->count = 1 + 1 + 1; // 左子树 root: 2
    root->rchild->count = 1 + 1;     // 右子树 root: 8
    root->count = 1 + 3 + 2;        // 根结点 root: 5

    return root;
}

int main() {
    BSTree myTree = BuildSampleTree();
    int n = myTree->count;

    printf("树中共有 %d 个结点。\n", n);
