    // 测试查找第 1 到第 n 小的元素
    for (int k = 1; k <= n + 1; k++) {
        BSTNode *result = FindKthSmallest(myTree, k);
        if (result != NULL) {
            printf("第 %d 小的元素是: %d\n", k, result->data);
        } else {
            printf("没有找到第 %d 小的元素 (k 越界)。\n", k);
        }
    }

    return 0;
}
